import React, { useState } from 'react';
import Dashboard from './Dashboard';
import { uploadDNA, submitManualData } from './api';

/**
 * App Component
 * Handles the view switching between DNA Upload and Manual Health Quiz.
 */
function App() {
    // Core State
    const [analysisData, setAnalysisData] = useState(null);
    const [isLoading, setIsLoading] = useState(false);
    const [view, setView] = useState('choice'); // 'choice', 'dna', or 'manual'
    const [error, setError] = useState(null);

    // Manual Assessment State
    const [goal, setGoal] = useState('Energy');
    const [symptoms, setSymptoms] = useState([]);

    // Data Constants
    const goals = ["Energy", "Immunity", "Cognitive Focus", "Skin Health", "Muscle Recovery"];
    const symptomList = [
        "Fatigue", "Stress", "Poor Sleep", "Muscle Cramps", 
        "Brain Fog", "Joint Pain", "Brittle Nails"
    ];

    // --- Logic Handlers ---

    const handleFileUpload = async (event) => {
        const file = event.target.files[0];
        if (!file) return;

        setIsLoading(true);
        setError(null);

        try {
            const response = await uploadDNA(file);
            if (response.status === "success") {
                setAnalysisData(response.data);
            } else {
                setError("Analysis failed. Please check the file format.");
            }
        } catch (err) {
            setError("Cannot connect to backend. Is main.py running?");
        } finally {
            setIsLoading(false);
        }
    };

    const handleManualSubmit = async () => {
        setIsLoading(true);
        setError(null);

        try {
            const response = await submitManualData({ goal, symptoms });
            if (response.status === "success") {
                setAnalysisData(response.data);
            }
        } catch (err) {
            setError("Backend connection failed.");
        } finally {
            setIsLoading(false);
        }
    };

    const toggleSymptom = (s) => {
        setSymptoms(prev => 
            prev.includes(s) ? prev.filter(i => i !== s) : [...prev, s]
        );
    };

    // --- Render Helpers ---

    return (
        <div style={styles.container}>
            <header style={styles.header}>
                <h1 style={styles.title}>NutriGen<span style={{color: '#38a169'}}>.</span></h1>
                <p style={styles.subtitle}>Precision nutrition based on your genetic and lifestyle markers.</p>
            </header>

            <main>
                {analysisData ? (
                    /* Show Dashboard if data exists */
                    <Dashboard data={analysisData} onReset={() => {setAnalysisData(null); setView('choice');}} />
                ) : view === 'choice' ? (
                    /* Initial Landing View */
                    <div style={styles.choiceGrid}>
                        <div style={styles.optionCard} onClick={() => setView('dna')}>
                            <div style={styles.icon}>🧬</div>
                            <h3>DNA Upload</h3>
                            <p>Import your raw .txt data from 23andMe or AncestryDNA for genetic insights.</p>
                        </div>
                        <div style={styles.optionCard} onClick={() => setView('manual')}>
                            <div style={styles.icon}>📝</div>
                            <h3>Health Quiz</h3>
                            <p>No genetic data? Get professional recommendations based on your symptoms.</p>
                        </div>
                    </div>
                ) : view === 'dna' ? (
                    /* DNA Upload View */
                    <div style={styles.card}>
                        <h3 style={styles.cardTitle}>Genomic Analysis</h3>
                        <p>Your privacy matters. Files are processed locally and never stored.</p>
                        <div style={{margin: '30px 0'}}>
                            <input type="file" onChange={handleFileUpload} id="dna-file-input" hidden accept=".txt" />
                            <label htmlFor="dna-file-input" style={isLoading ? styles.btnDisabled : styles.btn}>
                                {isLoading ? "Processing Genome..." : "Select DNA File (.txt)"}
                            </label>
                        </div>
                        <button onClick={() => setView('choice')} style={styles.backLink}>← Back to options</button>
                    </div>
                ) : (
                    /* Manual Quiz View */
                    <div style={styles.card}>
                        <h3 style={styles.cardTitle}>Lifestyle Assessment</h3>
                        <div style={styles.formGroup}>
                            <label style={styles.label}>What is your primary health goal?</label>
                            <select value={goal} onChange={(e) => setGoal(e.target.value)} style={styles.input}>
                                {goals.map(g => <option key={g} value={g}>{g}</option>)}
                            </select>
                        </div>
                        
                        <div style={styles.formGroup}>
                            <label style={styles.label}>Select current symptoms (Select all that apply):</label>
                            <div style={styles.tagContainer}>
                                {symptomList.map(s => (
                                    <button 
                                        key={s} 
                                        onClick={() => toggleSymptom(s)}
                                        style={symptoms.includes(s) ? styles.tagActive : styles.tag}
                                    >
                                        {s}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <button onClick={handleManualSubmit} style={styles.btn}>
                            {isLoading ? "Generating Recommendations..." : "View My Nutritional Plan"}
                        </button>
                        <button onClick={() => setView('choice')} style={styles.backLink}>← Back to options</button>
                    </div>
                )}
                {error && <p style={styles.errorText}>{error}</p>}
            </main>
        </div>
    );
}

// --- Modern Minimalist Styles ---
const styles = {
    container: { maxWidth: '900px', margin: '0 auto', padding: '60px 20px', fontFamily: "'Inter', sans-serif", color: '#1a202c' },
    header: { textAlign: 'center', marginBottom: '60px' },
    title: { fontSize: '3rem', fontWeight: '800', margin: 0, letterSpacing: '-1px' },
    subtitle: { color: '#718096', fontSize: '1.1rem', marginTop: '10px' },
    choiceGrid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '24px' },
    optionCard: { 
        padding: '50px 30px', border: '1px solid #e2e8f0', borderRadius: '24px', cursor: 'pointer', 
        transition: 'all 0.2s ease', background: '#fff', textAlign: 'center' 
    },
    icon: { fontSize: '2.5rem', marginBottom: '20px' },
    card: { background: '#f7fafc', padding: '50px', borderRadius: '24px', border: '1px solid #e2e8f0', textAlign: 'center' },
    cardTitle: { fontSize: '1.5rem', marginBottom: '20px' },
    formGroup: { textAlign: 'left', maxWidth: '500px', margin: '0 auto 30px' },
    label: { display: 'block', fontWeight: '600', marginBottom: '10px', color: '#4a5568' },
    input: { width: '100%', padding: '12px', borderRadius: '10px', border: '1px solid #cbd5e0', fontSize: '1rem' },
    tagContainer: { display: 'flex', gap: '10px', flexWrap: 'wrap' },
    tag: { padding: '8px 16px', borderRadius: '20px', border: '1px solid #cbd5e0', background: '#fff', cursor: 'pointer', transition: '0.2s' },
    tagActive: { padding: '8px 16px', borderRadius: '20px', border: '1px solid #38a169', background: '#e6fffa', color: '#2c7a7b', fontWeight: '600', cursor: 'pointer' },
    btn: { background: '#1a202c', color: '#fff', padding: '14px 40px', borderRadius: '12px', cursor: 'pointer', border: 'none', fontWeight: '600', fontSize: '1rem', transition: '0.2s' },
    btnDisabled: { background: '#a0aec0', color: '#fff', padding: '14px 40px', borderRadius: '12px', cursor: 'not-allowed', border: 'none' },
    backLink: { background: 'none', border: 'none', color: '#718096', cursor: 'pointer', textDecoration: 'underline', marginTop: '20px', display: 'block', width: '100%' },
    errorText: { color: '#e53e3e', marginTop: '20px', fontWeight: '500' }
};

export default App;
